+// Tile patterns for floor tiles
+const FLOOR_TILES = {
+  wood: [
+    (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => {
+      ctx.fillStyle = '#3e2a18';
+      ctx.fillRect(x, y, size, size);
+      ctx.fillStyle = '#4a3420';
+      ctx.fillRect(x + 2, y + 2, size - 4, size - 4);
+      ctx.fillStyle = 'rgba(0,0,0,0.08)';
+      ctx.fillRect(x + 4, y + 4, size - 8, 1);
+      ctx.fillRect(x + 4, y + size / 2, size - 8, 1);
+      ctx.fillRect(x + 4, y + size - 5, size - 8, 1);
+    },
+    (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => {
+      ctx.fillStyle = '#443018';
+      ctx.fillRect(x, y, size, size);
+      ctx.fillStyle = '#3a2614';
+      ctx.fillRect(x + 1, y + 1, size - 2, size - 2);
+      ctx.fillStyle = 'rgba(0,0,0,0.1)';
+      ctx.fillRect(x + 3, y + 3, size - 6, 1);
+      ctx.fillRect(x + 3, y + size / 2 + 1, size - 6, 1);
+      ctx.fillRect(x + 3, y + size - 4, size - 6, 1);
+    },
+  ],
+  stone: [
+    (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => {
+      ctx.fillStyle = '#2c3040';
+      ctx.fillRect(x, y, size, size);
+      ctx.fillStyle = '#343848';
+      ctx.fillRect(x + 1, y + 1, size - 2, size - 2);
+      ctx.fillStyle = 'rgba(0,0,0,0.2)';
+      ctx.fillRect(x + 4, y + 6, size - 8, 1);
+      ctx.fillRect(x + 7, y + 4, 1, size - 8);
+    },
+    (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => {
+      ctx.fillStyle = '#2a2e3a';
+      ctx.fillRect(x, y, size, size);
+      ctx.fillStyle = '#3a3e4a';
+      ctx.fillRect(x + 1, y + 1, size - 2, size - 2);
+      ctx.fillStyle = 'rgba(0,0,0,0.15)';
+      ctx.fillRect(x + 3, y + 5, size - 6, 1);
+      ctx.fillRect(x + 6, y + 3, 1, size - 6);
+    },
+  ],
+  dark_stone: [
+    (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => {
+      ctx.fillStyle = '#1a2030';
+      ctx.fillRect(x, y, size, size);
+      ctx.fillStyle = '#222838';
+      ctx.fillRect(x + 1, y + 1, size - 2, size - 2);
+      ctx.fillStyle = 'rgba(0,0,0,0.25)';
+      ctx.fillRect(x + 4, y + 6, size - 8, 1);
+      ctx.fillRect(x + 7, y + 4, 1, size - 8);
+    },
+    (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => {
+      ctx.fillStyle = '#1a1e2a';
+      ctx.fillRect(x, y, size, size);
+      ctx.fillStyle = '#242a38';
+      ctx.fillRect(x + 1, y + 1, size - 2, size - 2);
+      ctx.fillStyle = 'rgba(0,0,0,0.2)';
+      ctx.fillRect(x + 3, y + 5, size - 6, 1);
+      ctx.fillRect(x + 6, y + 3, 1, size - 6);
+    },
+  ],
+  carpet: [
+    (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => {
+      ctx.fillStyle = '#2c3040';
+      ctx.fillRect(x, y, size, size);
+      ctx.fillStyle = '#303848';
+      ctx.fillRect(x + 2, y + 2, size - 4, size - 4);
+      ctx.fillStyle = '#282e3e';
+      ctx.fillRect(x + size / 3, y + size / 3, size / 3, size / 3);
+    },
+    (ctx: CanvasRenderingContext2D, x: number, y: number, size: number) => {
+      ctx.fillStyle = '#282e3e';
+      ctx.fillRect(x, y, size, size);
+      ctx.fillStyle = '#303848';
+      ctx.fillRect(x + 1, y + 1, size - 2, size - 2);
+      ctx.fillStyle = '#2c3040';
+      ctx.fillRect(x + size / 4, y + size / 4, size / 2, size / 2);
+    },
+  ],
+};
