+function drawTiledFloor(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
+  const floorTypeMap: Record<CharacterType, string> = {
+    king: 'carpet', nobility: 'wood', knight: 'wood', squire: 'wood',
+    healer: 'dark_stone', sentinel: 'stone', scribe: 'wood', judge: 'wood', blacksmith: 'stone',
+  };
+  const tileSize = 16;
+  const kind = floorTypeMap[type];
+  if (!kind || !(kind in FLOOR_TILES)) {
+    ctx.fillStyle = '#000000';
+    ctx.fillRect(x, y, w, h);
+    return;
+  }
+  const tiles = FLOOR_TILES[kind as keyof typeof FLOOR_TILES];
+  const cols = Math.ceil(w / tileSize);
+  const rows = Math.ceil(h / tileSize);
+  for (let r = 0; r < rows; r++) {
+    for (let c = 0; c < cols; c++) {
+      const tx = x + c * tileSize;
+      const ty = y + r * tileSize;
+      // Select tile pattern by hash for variation
+      const hash = ((c * 17 + r * 31) & 0xFF) / 255;
+      const tileIndex = Math.floor(hash * tiles.length);
+      const tileDraw = tiles[tileIndex % tiles.length];
+      tileDraw(ctx, tx, ty, tileSize);
+      // Add cracks or cracks pattern for stone tiles
+      if (kind === 'stone' || kind === 'dark_stone') {
+        if (hash > 0.7) {
+          ctx.strokeStyle = 'rgba(0,0,0,0.3)';
+          ctx.lineWidth = 1;
+          ctx.beginPath();
+          ctx.moveTo(tx + 3, ty + 3);
+          ctx.lineTo(tx + tileSize - 4, ty + tileSize - 4);
+          ctx.moveTo(tx + tileSize - 4, ty + 3);
+          ctx.lineTo(tx + 3, ty + tileSize - 4);
+          ctx.stroke();
+        }
+      }
+      // Add subtle color variation for wood tiles
+      if (kind === 'wood') {
+        const shade = 0.05 * Math.sin((c + r) * 3.14);
+        ctx.fillStyle = `rgba(0,0,0,${shade})`;
+        ctx.fillRect(tx, ty, tileSize, tileSize);
+      }
+      // Add pattern dots for carpet tiles
+      if (kind === 'carpet') {
+        ctx.fillStyle = 'rgba(255, 215, 0, 0.1)';
+        ctx.beginPath();
+        ctx.arc(tx + tileSize / 2, ty + tileSize / 2, 2, 0, Math.PI * 2);
+        ctx.fill();
+      }
+    }
+  }
+  // Draw subtle overlay grid lines for tile edges
+  ctx.strokeStyle = 'rgba(0,0,0,0.1)';
+  ctx.lineWidth = 1;
+  for (let r = 0; r <= rows; r++) {
+    ctx.beginPath();
+    ctx.moveTo(x, y + r * tileSize);
+    ctx.lineTo(x + w, y + r * tileSize);
+    ctx.stroke();
+  }
+  for (let c = 0; c <= cols; c++) {
+    ctx.beginPath();
+    ctx.moveTo(x + c * tileSize, y);
+    ctx.lineTo(x + c * tileSize, y + h);
+    ctx.stroke();
+  }
+}
